<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        body {
            background-color: #121212;
            color: #eee;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            margin: 0;
            overflow: hidden;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
        }

        #canvas-container {
            position: relative;
            box-shadow: 0 0 30px rgba(0,0,0,0.5);
            border: 4px solid #333;
            line-height: 0;
        }

        canvas {
            background-color: #1a1a1a;
            cursor: crosshair;
            image-rendering: pixelated;
        }

        .controls {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
            max-width: 600px;
        }

        button {
            padding: 10px 20px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            text-transform: uppercase;
            transition: all 0.2s ease;
            box-shadow: 0 2px 5px rgba(0,0,0,0.3);
            outline: none;
        }

        button:active {
            transform: translateY(2px);
            box-shadow: none;
        }

        /* Material Buttons */
        #mat-sand  { background-color: #e3b448; color: #000; }
        #mat-water { background-color: #3498db; color: #fff; }
        #mat-wall  { background-color: #7f8c8d; color: #fff; }
        #mat-acid  { background-color: #2ecc71; color: #000; }
        #mat-empty { background-color: #444;    color: #fff; }
        #clear     { background-color: #e74c3c; color: #fff; margin-left: 20px; }

        button.active {
            outline: 3px solid white;
            box-shadow: 0 0 15px rgba(255,255,255,0.4);
            transform: scale(1.1);
        }

        h1 {
            margin: 0 0 10px 0;
            font-weight: 300;
            letter-spacing: 2px;
            color: #aaa;
        }
    </style>
</head>
<body>

    <div class="container">
        <h1>SANDBOX</h1>
        <div id="canvas-container">
            <canvas id="sand"></canvas>
        </div>
        <div class="controls">
            <button id="mat-sand" class="active">Sand</button>
            <button id="mat-water">Water</button>
            <button id="mat-wall">Wall</button>
            <button id="mat-acid">Acid</button>
            <button id="mat-empty">Eraser</button>
            <button id="clear">Clear Grid</button>
        </div>
    </div>

    <script>
        (function() {
            const W = 100;
            const H = 100;
            const CELL_SIZE = 5; // Visual scale
            const canvas = document.getElementById('sand');
            const ctx = canvas.getContext('2d', { alpha: false });

            canvas.width = W * CELL_SIZE;
            canvas.height = H * CELL_SIZE;

            // Material IDs
            const MAT = {
                empty: 0,
                sand: 1,
                water: 2,
                wall: 3,
                acid: 4
            };

            const MAT_NAMES = ['empty', 'sand', 'water', 'wall', 'acid'];
            const COLORS = {
                0: '#1a1a1a', // empty
                1: '#e3b448', // sand
                2: '#3498db', // water
                3: '#7f8c8d', // wall
                4: '#2ecc71'  // acid
            };

            let grid = new Int8Array(W * H).fill(0);
            let currentMaterial = 'sand';

            // API Implementation
            window.sim = {
                w: W,
                h: H,
                get: (x, y) => {
                    if (x < 0 || x >= W || y < 0 || y >= H) return 'empty';
                    return MAT_NAMES[grid[y * W + x]];
                },
                set: (x, y, material) => {
                    if (x < 0 || x >= W || y < 0 || y >= H) return;
                    const matId = MAT[material];
                    if (matId === undefined) return;
                    grid[y * W + x] = matId;
                },
                clear: () => {
                    grid.fill(0);
                },
                tick: (n = 1) => {
                    for (let i = 0; i < n; i++) {
                        updateSimulation();
                    }
                }
            };

            function updateSimulation() {
                // Process bottom-up to prevent teleporting and ensure gravity consistency
                for (let y = H - 1; y >= 0; y--) {
                    // Randomize X direction each frame to avoid directional bias
                    const xDir = Math.random() > 0.5 ? 1 : -1;
                    for (let x = 0; x < W; x++) {
                        const idx = y * W + x;
                        const type = grid[idx];

                        if (type === MAT.empty || type === MAT.wall) continue;

                        // SAND LOGIC
                        if (type === MAT.sand) {
                            if (y < H - 1) {
                                const below = (y + 1) * W + x;
                                if (grid[below] === MAT.empty) {
                                    grid[below] = MAT.sand;
                                    grid[idx] = MAT.empty;
                                } else if (grid[below] === MAT.water || grid[below] === MAT.acid) {
                                    // Sinking: Swap sand with liquid
                                    const temp = grid[below];
                                    grid[below] = MAT.sand;
                                    grid[idx] = temp;
                                } else {
                                    // Slide diagonally
                                    const left = (y + 1) * W + (x - 1);
                                    const right = (y + 1) * W + (x + 1);
                                    const first = Math.random() > 0.5 ? left : right;
                                    const second = first === left ? right : left;

                                    if (x > 0 && (grid[first] === MAT.empty || grid[first] === MAT.water || grid[first] === MAT.acid)) {
                                        const temp = grid[first];
                                        grid[first] = MAT.sand;
                                        grid[idx] = temp;
                                    } else if (x < W - 1 && (grid[second] === MAT.empty || grid[second] === MAT.water || grid[second] === MAT.acid)) {
                                        const temp = grid[second];
                                        grid[second] = MAT.sand;
                                        grid[idx] = temp;
                                    }
                                }
                            }
                        } 
                        // WATER LOGIC
                        else if (type === MAT.water) {
                            if (y < H - 1 && grid[(y + 1) * W + x] === MAT.empty) {
                                grid[(y + 1) * W + x] = MAT.water;
                                grid[idx] = MAT.empty;
                            } else {
                                // Spread horizontally
                                const left = y * W + (x - 1);
                                const right = y * W + (x + 1);
                                if (x > 0 && grid[left] === MAT.empty) {
                                    grid[left] = MAT.water;
                                    grid[idx] = MAT.empty;
                                } else if (x < W - 1 && grid[right] === MAT.empty) {
                                    grid[right] = MAT.water;
                                    grid[idx] = MAT.empty;
                                }
                            }
                        }
                        // ACID LOGIC
                        else if (type === MAT.acid) {
                            // Dissolve logic: check below and sides
                            const targets = [];
                            if (y < H - 1) targets.push((y + 1) * W + x);
                            if (x > 0) targets.push(y * W + (x - 1));
                            if (x < W - 1) targets.push(y * W + (x + 1));

                            let dissolved = false;
                            for (let tIdx of targets) {
                                if (grid[tIdx] === MAT.sand || grid[tIdx] === MAT.wall) {
                                    grid[tIdx] = MAT.empty;
                                    grid[idx] = MAT.empty; // Acid is consumed in reaction
                                    dissolved = true;
                                    break;
                                }
                            }

                            if (!dissolved) {
                                // Move like water
                                if (y < H - 1 && grid[(y + 1) * W + x] === MAT.empty) {
                                    grid[(y + 1) * W + x] = MAT.acid;
                                    grid[idx] = MAT.empty;
                                } else {
                                    const left = y * W + (x - 1);
                                    const right = y * W + (x + 1);
                                    if (x > 0 && grid[left] === MAT.empty) {
                                        grid[left] = MAT.acid;
                                        grid[idx] = MAT.empty;
                                    } else if (x < W - 1 && grid[right] === MAT.empty) {
                                        grid[right] = MAT.acid;
                                        grid[idx] = MAT.empty;
                                    }
                                }
                            }
                        }
                    }
                }
            }

            function render() {
                ctx.fillStyle = COLORS[0];
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                for (let y = 0; y < H; y++) {
                    for (let x = 0; x < W; x++) {
                        const type = grid[y * W + x];
                        if (type !== MAT.empty) {
                            ctx.fillStyle = COLORS[type];
                            ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                        }
                    }
                }
            }

            // Input Handling
            let isPainting = false;
            const handleInput = (e) => {
                if (!isPainting) return;
                const rect = canvas.getBoundingClientRect();
                const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
                const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
                window.sim.set(x, y, currentMaterial);
            };

            canvas.addEventListener('mousedown', (e) => { isPainting = true; handleInput(e); });
            window.addEventListener('mouseup', () => { isPainting = false; });
            canvas.addEventListener('mousemove', handleInput);

            // UI Buttons
            const matBtns = ['mat-sand', 'mat-water', 'mat-wall', 'mat-acid', 'mat-empty'];
            matBtns.forEach(id => {
                document.getElementById(id).addEventListener('click', (e) => {
                    currentMaterial = id.replace('mat-', '');
                    matBtns.forEach(btnId => document.getElementById(btnId).classList.remove('active'));
                    e.target.classList.add('active');
                });
            });

            document.getElementById('clear').addEventListener('click', () => {
                window.sim.clear();
            });

            // Main Loop
            function loop() {
                window.sim.tick(1);
                render();
                requestAnimationFrame(loop);
            }

            loop();
        })();
    </script>
</body>
</html>
